// Initialize app
class YohmurLiveApp {
    constructor() {
        this.data = this.loadData();
        this.filteredBusinesses = [...this.data.businesses];
        this.currentFilter = 'all';
        this.currentSort = 'newest';
        this.init();
    }

    // Load data from localStorage or use default
    loadData() {
        const stored = localStorage.getItem('yohmor_data');
        if (stored) {
            try {
                return JSON.parse(stored);
            } catch (e) {
                console.error('Error loading data:', e);
                return DEFAULT_DATA;
            }
        }
        return DEFAULT_DATA;
    }

    // Save data to localStorage
    saveData() {
        localStorage.setItem('yohmor_data', JSON.stringify(this.data));
    }

    // Initialize app
    init() {
        this.setupEventListeners();
        this.renderBusinesses();
        this.updateNotificationBadge();
        this.checkForNewNotifications();
    }

    // Setup event listeners
    setupEventListeners() {
        // Search
        const searchInput = document.getElementById('searchInput');
        if (searchInput) {
            searchInput.addEventListener('input', (e) => this.handleSearch(e.target.value));
        }

        // Filters
        const filterBtns = document.querySelectorAll('.filter-btn');
        filterBtns.forEach(btn => {
            btn.addEventListener('click', (e) => this.handleFilter(e.target.dataset.filter));
        });

        // Sort
        const sortSelect = document.getElementById('sortSelect');
        if (sortSelect) {
            sortSelect.addEventListener('change', (e) => this.handleSort(e.target.value));
        }

        // Notification button
        const notificationBtn = document.getElementById('notificationBtn');
        if (notificationBtn) {
            notificationBtn.addEventListener('click', () => this.showLatestNotification());
        }

        // Modal close
        const modalClose = document.getElementById('modalClose');
        if (modalClose) {
            modalClose.addEventListener('click', () => this.closeModal());
        }

        const closeNotification = document.getElementById('closeNotification');
        if (closeNotification) {
            closeNotification.addEventListener('click', () => this.closeNotificationPopup());
        }

        // Close modal on background click
        const modal = document.getElementById('businessModal');
        if (modal) {
            modal.addEventListener('click', (e) => {
                if (e.target === modal) {
                    this.closeModal();
                }
            });
        }
    }

    // Handle search
    handleSearch(query) {
        const searchTerm = query.toLowerCase().trim();
        
        this.filteredBusinesses = this.data.businesses.filter(business => {
            const matchesSearch = !searchTerm || 
                business.name.toLowerCase().includes(searchTerm) ||
                business.description.toLowerCase().includes(searchTerm) ||
                business.tags.some(tag => tag.toLowerCase().includes(searchTerm));
            
            const matchesFilter = this.currentFilter === 'all' || business.category === this.currentFilter;
            
            return matchesSearch && matchesFilter;
        });

        this.applySort();
        this.renderBusinesses();
    }

    // Handle filter
    handleFilter(filter) {
        this.currentFilter = filter;

        // Update active button
        document.querySelectorAll('.filter-btn').forEach(btn => {
            btn.classList.remove('active');
            if (btn.dataset.filter === filter) {
                btn.classList.add('active');
            }
        });

        // Apply filter
        const searchTerm = document.getElementById('searchInput').value.toLowerCase().trim();
        
        this.filteredBusinesses = this.data.businesses.filter(business => {
            const matchesSearch = !searchTerm || 
                business.name.toLowerCase().includes(searchTerm) ||
                business.description.toLowerCase().includes(searchTerm) ||
                business.tags.some(tag => tag.toLowerCase().includes(searchTerm));
            
            const matchesFilter = filter === 'all' || business.category === filter;
            
            return matchesSearch && matchesFilter;
        });

        this.applySort();
        this.renderBusinesses();
    }

    // Handle sort
    handleSort(sortType) {
        this.currentSort = sortType;
        this.applySort();
        this.renderBusinesses();
    }

    // Apply sort
    applySort() {
        if (this.currentSort === 'newest') {
            this.filteredBusinesses.sort((a, b) => 
                new Date(b.createdAt) - new Date(a.createdAt)
            );
        } else if (this.currentSort === 'name') {
            this.filteredBusinesses.sort((a, b) => 
                a.name.localeCompare(b.name, 'ar')
            );
        }
    }

    // Render businesses
    renderBusinesses() {
        const grid = document.getElementById('businessesGrid');
        const noResults = document.getElementById('noResults');

        if (!grid) return;

        if (this.filteredBusinesses.length === 0) {
            grid.innerHTML = '';
            noResults.style.display = 'block';
            return;
        }

        noResults.style.display = 'none';
        grid.innerHTML = this.filteredBusinesses.map(business => `
            <div class="business-card" onclick="app.openModal('${business.id}')">
                <img src="${business.image}" alt="${business.name}" class="business-image" onerror="this.src='data:image/svg+xml,%3Csvg xmlns=%22http://www.w3.org/2000/svg%22 width=%22400%22 height=%22300%22%3E%3Crect fill=%22%23E8F5E9%22 width=%22400%22 height=%22300%22/%3E%3Ctext x=%2250%25%22 y=%2250%25%22 font-size=%2248%22 fill=%22%230B8A4B%22 text-anchor=%22middle%22 dy=%22.3em%22%3E📷%3C/text%3E%3C/svg%3E'">
                <div class="business-body">
                    <span class="business-category">${business.category}</span>
                    <h3 class="business-name">${business.name}</h3>
                    <p class="business-description">${business.description}</p>
                    <div class="business-footer">
                        <a href="https://wa.me/${business.whatsapp.replace(/\D/g, '')}" target="_blank" class="business-btn business-whatsapp">💬 واتساب</a>
                        <button class="business-btn business-details">📋 التفاصيل</button>
                    </div>
                </div>
            </div>
        `).join('');
    }

    // Open modal
    openModal(businessId) {
        const business = this.data.businesses.find(b => b.id === businessId);
        if (!business) return;

        document.getElementById('modalImage').src = business.image;
        document.getElementById('modalImage').alt = business.name;
        document.getElementById('modalName').textContent = business.name;
        document.getElementById('modalCategory').textContent = business.category;
        document.getElementById('modalDescription').textContent = business.description;
        document.getElementById('modalAddress').textContent = business.address || 'غير محدد';
        document.getElementById('modalHours').textContent = business.hours || 'غير محدد';

        // WhatsApp button
        const whatsappBtn = document.getElementById('modalWhatsapp');
        whatsappBtn.href = `https://wa.me/${business.whatsapp.replace(/\D/g, '')}`;

        // Website button
        const websiteBtn = document.getElementById('modalWebsite');
        if (business.website) {
            websiteBtn.href = business.website;
            websiteBtn.style.display = 'inline-block';
        } else {
            websiteBtn.style.display = 'none';
        }

        // Show modal
        const modal = document.getElementById('businessModal');
        modal.classList.add('show');
        document.body.style.overflow = 'hidden';
    }

    // Close modal
    closeModal() {
        const modal = document.getElementById('businessModal');
        modal.classList.remove('show');
        document.body.style.overflow = 'auto';
    }

    // Update notification badge
    updateNotificationBadge() {
        const newCount = this.data.notifications.filter(n => {
            const notificationTime = new Date(n.date);
            const lastCheck = localStorage.getItem('last_notification_check');
            return !lastCheck || notificationTime > new Date(lastCheck);
        }).length;

        const badge = document.getElementById('notificationBadge');
        if (badge) {
            badge.textContent = newCount;
            badge.style.display = newCount > 0 ? 'inline-flex' : 'none';
        }
    }

    // Check for new notifications
    checkForNewNotifications() {
        const lastCheck = localStorage.getItem('last_notification_check');
        const notifications = this.data.notifications.sort((a, b) => 
            new Date(b.date) - new Date(a.date)
        );

        if (notifications.length > 0) {
            const latest = notifications[0];
            const latestTime = new Date(latest.date);
            
            if (!lastCheck || latestTime > new Date(lastCheck)) {
                // Auto-show notification popup after 2 seconds
                setTimeout(() => {
                    this.showNotification(latest);
                }, 2000);
            }
        }

        localStorage.setItem('last_notification_check', new Date().toISOString());
    }

    // Show latest notification
    showLatestNotification() {
        const notifications = this.data.notifications.sort((a, b) => 
            new Date(b.date) - new Date(a.date)
        );

        if (notifications.length > 0) {
            this.showNotification(notifications[0]);
        }
    }

    // Show notification popup
    showNotification(notification) {
        document.getElementById('notificationTitle').textContent = notification.title;
        document.getElementById('notificationMessage').textContent = notification.message;
        
        const dateObj = new Date(notification.date);
        const dateStr = dateObj.toLocaleDateString('ar-SA', {
            year: 'numeric',
            month: 'long',
            day: 'numeric',
            hour: '2-digit',
            minute: '2-digit'
        });
        document.getElementById('notificationDate').textContent = dateStr;

        const popup = document.getElementById('notificationPopup');
        popup.classList.add('show');

        // Auto-hide after 8 seconds
        setTimeout(() => {
            this.closeNotificationPopup();
        }, 8000);
    }

    // Close notification popup
    closeNotificationPopup() {
        const popup = document.getElementById('notificationPopup');
        popup.classList.remove('show');
    }
}

// Initialize app when DOM is ready
document.addEventListener('DOMContentLoaded', () => {
    window.app = new YohmurLiveApp();
});
